#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
typedef long long LL;
namespace IO 
{
	inline int read()
	{
		int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
	}
	inline void p(LL x){if(x>9)p(x/10);putchar(x%10+'0');}
	inline void print(LL x,char ch){p(x);putchar(ch);}
}
using IO::read; using IO::print;
const int N=2e5+10;int n,A,B,rcy;int len[N],slen[N],res[N];
struct Seg{int l,r,mn;}t[N<<5];int Rt,cnt;
inline void add(int pos,int val,int l=0,int r=rcy-1,int &cur=Rt)
{
	if(!cur)cur=++cnt;t[cur].mn=val;if(l==r)return;int mid=(l+r)>>1;
	pos<=mid?add(pos,val,l,mid,t[cur].l):add(pos,val,mid+1,r,t[cur].r);
}
inline int qry(int ql,int qr,int l=0,int r=rcy-1,int cur=Rt)
{
	if(!cur)return n+1;if(ql<=l&&r<=qr)return t[cur].mn;int mid=(l+r)>>1;
	int mn=n+1;if(ql<=mid)mn=min(mn,qry(ql,qr,l,mid,t[cur].l));
	if(qr>mid)mn=min(mn,qry(ql,qr,mid+1,r,t[cur].r));return mn;
}
inline int Dis(int l,int r){return r==n+1?slen[r]-slen[l]:(slen[r]-slen[l]-1+rcy)/rcy*rcy;}
signed main()
{
	n=read(),A=read(),B=read(),rcy=A+B;
	rep(1,n+1,i)slen[i]=slen[i-1]+(len[i]=read());
	drep(n,1,i)
	{
		int ql=(slen[i]%rcy+A)%rcy,qr=(ql+B-1+rcy)%rcy;
		int pos=ql>qr?min(qry(ql,rcy-1),qry(0,qr)):qry(ql,qr);
		res[i]=Dis(i,pos)+res[pos];add(slen[i]%rcy,i);
	}
	int Q=read();while(Q--)
	{
		int x=read();int ql=(A-x%rcy+rcy)%rcy,qr=(ql+B-1+rcy)%rcy;
		int pos=ql>qr?min(qry(ql,rcy-1),qry(0,qr)):qry(ql,qr);
		slen[0]=-x;printf("%lld\n",Dis(0,pos)+res[pos]);
	}
	return 0;
}
